import '../styles/App.css';
import Banner from './Banner';

function App() {
  return (
    <div className="App">
      <Banner 
        title="Sneakers Collection" 
        subtitle="Découvrez les dernières tendances streetwear"
      />
      <main className="App-main">
        <p>
          Bienvenue dans votre application de collection de sneakers !
        </p>
        {/* Ici vous pourrez ajouter d'autres composants comme une galerie de sneakers */}
      </main>
    </div>
  );
}

export default App;
